import java.util.*;

class DetectSquares {
    Map<Integer, Map<Integer, Integer>> points;

    public DetectSquares() {
        points = new HashMap<>();
    }

    public void add(int[] point) {
        points.computeIfAbsent(point[0], k -> new HashMap<>()).put(point[1], points.get(point[0]).getOrDefault(point[1], 0) + 1);
    }

    public int count(int[] point) {
        int ans = 0;
        for (int x2 : points.keySet()) {
            if (!points.get(point[0]).containsKey(x2) || x2 == point[1]) continue;
            for (int y2 : points.get(x2).keySet()) {
                if (y2 == point[0] || Math.abs(x2 - point[1]) != Math.abs(y2 - point[0])) continue;
                ans += points.get(point[0]).get(x2) * points.get(x2).get(y2) * points.get(point[0]).getOrDefault(y2, 0);
            }
        }
        return ans;
    }
}
